ult(1) // 1-5\n  industry     String    @default(\"general\") // general | healthcare | legal | financial | enterprise\n  grantedAt    DateTime  @default(now())\n  expiresAt    DateTime?\n  restrictions Json? // additional constraints at this clearance level\n\n  wallet Wallet @relation(fields: [walletId], references: [id])\n  agent  Agent  @relation(fields: [agentId], references: [id])\n\n  @@unique([walletId, agentId])\n  @@unique([agentId])\n  @@index([agentId])\n}\n\n// Short-lived JWT issued per execution — bounded scope, 15min TTL\nmodel ExecutionToken {\n  id          String    @id // = jti (JWT ID, unique per issuance)\n  agentId     String\n  walletId    String\n  scope       String[] // which credential labels this token can inject\n  budgetUsd   Float // spend authority for this execution\n  spentUsd    Float     @default(0)\n  clearance   Int       @default(1)\n  issuedAt    DateTime  @default(now())\n  expiresAt   DateTime\n  revokedAt   DateTime?\n  containerId String? // set when a docker container claims this token\n  status      String    @default(\"active\") // active | expired | revoked | completed\n\n  agent      Agent                 @relation(fields: [agentId], references: [id])\n  wallet     Wallet                @relation(fields: [walletId], references: [id])\n  injections CredentialInjection[]\n\n  @@index([agentId])\n  @@index([status, expiresAt])\n}\n\n// Audit record of every credential injection — what was accessed, when, by whom\nmodel CredentialInjection {\n  id               String   @id @default(cuid())\n  executionTokenId String\n  credentialId     String\n  injectedAt       DateTime @default(now())\n\n  executionToken ExecutionToken  @relation(fields: [executionTokenId], references: [id])\n  credential     CredentialVault @relation(fields: [credentialId], references: [id])\n\n  @@index([executionTokenId])\n}\n\nmodel AuthorizationRequest {\n  id             String    @id @default(cuid())\n  agentId        String\n  action         String // purchase | subscribe | transfer\n  amountUsd      Float\n  merchant       String\n  category       String\n  description    String?\n  status         String    @default(\"pending\") // pending | approved | denied | escalated\n  decidedAt      DateTime?\n  decisionNote   String?\n  idempotencyKey String? // client-supplied; dedupes retries per agent\n  createdAt      DateTime  @default(now())\n\n  agent Agent @relation(fields: [agentId], references: [id])\n\n  @@unique([agentId, idempotencyKey])\n  @@index([agentId, createdAt])\n  @@index([status])\n}\n\n// Awareness-stage marketing lead — captured before signup, owned in our DB so we\n// can message the list ourselves. Unique email = idempotent capture.\nmodel Lead {\n  id        String   @id @default(cuid())\n  email     String   @unique\n  source    String? // where it was captured: landing, hn, etc.\n  createdAt DateTime @default(now())\n\n  @@index([createdAt])\n}\n\n// Public, build-in-public feature request. Submitted by users on /roadmap, then\n// curated: only isPublished ideas show on the board. status drives the column it\n// appears in and ties the board to the published roadmap. authorEmail is captured\n// for follow-up (also mirrored into Lead) but never rendered publicly.\nmodel Idea {\n  id          String   @id @default(cuid())\n  title       String\n  detail      String?\n  category    String?\n  status      String   @default(\"open\") // open | planned | in_progress | shipped | declined\n  voteCount   Int      @default(0) // denormalized for ordering; source of truth is votes\n  isPublished Boolean  @default(false) // moderation gate — only published ideas are public\n  authorEmail String? // captured for follow-up, never shown publicly\n  createdAt   DateTime @default(now())\n\n  votes IdeaVote[]\n\n  @@index([isPublished, voteCount])\n  @@index([createdAt])\n}\n\n// One vote per voter per idea. voterKey is \"e:<email>\" when an email is given,\n// else \"ip:<sha256(ip)>\" — approximate d